-- W1.6 questions batch 4749/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-4c199b1b-moex-00023', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '遺產分割後，其未清償之被繼承人之債務，移歸一定之人承受，或劃歸各繼承人分擔，如經債權 人同意者，各繼承人得免除何種責任？', '["連帶保證", "連帶責任", "連帶債權", "侵權責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00024', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲、乙為夫妻，無子女。甲之父母均已死亡，甲有兄弟丙、丁二人。甲生前曾向丙借款新臺幣（下 同）40萬元，尚未清償。甲死亡時，留有遺產200萬元。遺產分割時，丙可分得多少財產？', '["60萬元", "70萬元", "80萬元", "90萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00025', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲男乙女於民國112年1月間結婚，甲於結婚前，有勞力所得新臺幣（下同）60萬元。下列關於 夫妻財產之敘述，何者正確？', '["設甲乙約定採共同財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙約定採分別財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙未約定夫妻財產制，甲勞力所得之60萬元，由甲乙公同共有", "設甲乙約定採勞力所得共同財產制，甲勞力所得之60萬元，由甲單獨所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00026', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '未婚之甲女與乙男發生性關係後懷孕並產下丙。丙成年後找到乙，要求乙為認領。乙表示其生活 窮困，若丙願扶養，則乙願認領。下列敘述，何者正確？', '["認領後，如丙確有受扶養必要，乙有扶養能力，乙應扶養丙", "認領後，如乙確實無謀生能力但尚非無法維持生活，丙仍應扶養乙", "認領後，如乙確有受扶養必要，甲丙應共同扶養乙", "認領經雙方意思表示合致成立，乙所附條件為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00027', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲乙為夫妻，生有A、B二子，並收養C為養女。乙於民國108年間死亡。今甲死亡，下列敘述， 何者正確？', '["A如對甲有重大之虐待或侮辱情事，經B及C共同表示A不得繼承；A則喪失其對甲之繼承權", "A及B於乙死亡後，否認C之繼承資格，並排除其對繼承財產之占有，C自知悉其得繼承之 時起2年間，得行使遺產酌給請求權", "B如有以詐欺或脅迫，使甲為關於繼承遺囑之情事，B則喪失其對甲之繼承權。但經甲宥恕者， 其繼承權不喪失", "甲如未立遺囑，C之應繼分為甲遺產之五分之一，A及B之應繼分各為甲遺產之五分之二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00028', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-113-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'essay', '甲有 A 屋一間，因已閒置一年，決定出租。乙見 A 屋地段佳，甚為喜
歡，而與甲簽訂租賃契約承租 A屋，雙方約定租賃期間自民國 112 年 7
月 1 日起至民國 114 年 6 月 30 日止，乙當場支付三個月租金總額之押
租金予甲，並於隔日搬入居住。甲於民國113 年2 月 1 日將 A屋出售於
丙，並辦理所有權移轉登記完畢，丙以其為 A屋所有權人且未出租於乙
為由，要求乙搬離，乙則以其係向甲承租為由斷然拒絕，何人之主張有
理由？若丙未要求乙搬離，當租賃期間屆滿，乙搬離時，可否請求丙返
還押租金？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00029', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-113-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'essay', '甲、乙、丙共有A地一筆，應有部分各為三分之一。於民國 112年 9 月
起，丁未得共有人之同意，擅自於該地劃設三十個停車位，並以每個月
租金新臺幣五千元對外出租，三十個車位當即全數出租。甲於民國 113
年 3 月發現 A 地為丁所占用，甲可否要求丁將 A 地及占用 A 地期間所
收取租金返還於自己？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00030', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-113-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '未保留胎兒應繼分之遺產協議分割行為，其效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00031', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-113-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲將一平板電腦借乙使用，乙使用時，好友丙見到，非常羨慕，表示願以高價購買之，乙見機不 可失，遂以自己名義賣與丙，並將該平板電腦交付於丙。有關乙、丙間之法律行為，下列敘述， 何者正確？', '["債權行為與物權行為均無效", "債權行為與物權行為均效力未定", "債權行為效力未定，物權行為無效", "債權行為有效，物權行為效力未定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00032', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-113-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列何種請求權，有消滅時效規定之適用？', '["分割共有物之請求權", "已登記不動產所有人之除去妨害請求權", "夫妻間侵權行為而生之損害賠償請求權", "夫妻關係而生之同居請求權 32020"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "921f497e6a6a", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL)
